async (params, browser) => {
  // Open hotel page with dates and guests
  await browser.open(`${params.hotel_url}?checkin=${params.checkin}&checkout=${params.checkout}&group_adults=${params.guests}&no_rooms=1`)

  // Wait for hotel page to load
  await browser.waitForSelector('h2.pp-header__title, [data-testid=\'header-title\'], .hp__hotel-name, #hp_hotel_name', 15000)

  // Let availability data render
  await browser.wait(3000)

  // Scroll to availability table
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further for all room options
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract room availability
  const availability_data = await browser.evaluate(`const nameEl = document.querySelector('h2.pp-header__title, [data-testid="header-title"], .hp__hotel-name, #hp_hotel_name'); const hotelName = nameEl ? nameEl.textContent.trim() : ''; const soldOutEl = document.querySelector('[data-testid="no-availability-message"], .sold-out-message, .hp--soldout, #availability_warning'); const isSoldOut = !!soldOutEl; const rooms = []; const roomBlocks = document.querySelectorAll('.hprt-table tr, [data-testid="availability-row"], table.hprt-table tbody tr, .js-rt-block-row'); roomBlocks.forEach(function(el, idx) { if (idx >= 25) return; const roomNameEl = el.querySelector('.hprt-roomtype-icon-link, [data-testid="room-type-link"], a.hprt-roomtype-link, .room_link strong'); const priceEl = el.querySelector('.hprt-price-price, [data-testid="price-and-discounted-price"], .bui-price-display__value'); const originalPriceEl = el.querySelector('.hprt-price-price-original, .bui-price-display__original'); const occupancyEl = el.querySelector('.hprt-occupancy-occupancy-info, [data-testid="occupancy-popup"]'); const bedEl = el.querySelector('.hprt-roomtype-bed, .hprt-bedcell, [data-testid="bed-type"]'); const mealEl = el.querySelector('.hprt-mealplan, [data-testid="meal-plan"], .hprt-board-type'); const cancellationEl = el.querySelector('.hprt-conditions, [data-testid="cancellation-policy"]'); const roomSizeEl = el.querySelector('.hprt-roomtype-room-size, [data-testid="room-size"]'); const roomFacilities = []; const facilityEls = el.querySelectorAll('.hprt-facilities-facility, [data-testid="room-facility"] span'); facilityEls.forEach(function(f) { const text = f.textContent.trim(); if (text && text.length > 1) roomFacilities.push(text); }); const selectEl = el.querySelector('.hprt-nos-select, select[data-testid="select-room-trigger"]'); const isAvailable = !el.querySelector('.hprt-sold-out, [data-testid="sold-out"]'); if (roomNameEl || priceEl) { rooms.push({ room_type: roomNameEl ? roomNameEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', bed_type: bedEl ? bedEl.textContent.trim() : '', max_occupancy: occupancyEl ? occupancyEl.textContent.trim() : '', room_size: roomSizeEl ? roomSizeEl.textContent.trim() : '', meal_plan: mealEl ? mealEl.textContent.trim() : '', cancellation: cancellationEl ? cancellationEl.textContent.trim().substring(0, 200) : '', facilities: roomFacilities.slice(0, 10), available: isAvailable }); } }); const taxInfoEl = document.querySelector('.hprt-price-tax-rate, [data-testid="taxes-and-charges"]'); return { hotel_name: hotelName, checkin: params.checkin, checkout: params.checkout, guests: params.guests || '2', is_sold_out: isSoldOut, sold_out_message: soldOutEl ? soldOutEl.textContent.trim() : '', tax_info: taxInfoEl ? taxInfoEl.textContent.trim() : '', available_room_count: rooms.filter(function(r) { return r.available; }).length, total_room_count: rooms.length, rooms: rooms, url: window.location.href }`)

  return availability_data
}
